// Build the rendered system prompt by replacing {{VARIABLES}} with values from Airtable + Unsplash.
const topic = $('Airtable: Get next topic').item.json.fields;
const unsplash = $('Unsplash: Search cover').item.json;
const systemPromptTemplate = $('Fetch system prompt').item.json.data || $('Fetch system prompt').item.json;

const today = new Date().toISOString().slice(0, 10);

// Pick first result; fall back to a default if none.
const firstPhoto = (unsplash.results && unsplash.results[0]) || null;
const coverUrl = firstPhoto
  ? firstPhoto.urls.regular
  : 'https://images.unsplash.com/photo-1505691938895-1758d7feb511?w=1600&q=80';
const coverAlt = firstPhoto
  ? (firstPhoto.alt_description || firstPhoto.description || 'Sydney home interior')
  : 'Sydney home interior';

// AVAILABLE_INTERNAL_LINKS — for the seed batch we pass a static list.
const availableInternalLinks = JSON.stringify([
  '/', '/membership',
  '/services/plumbing', '/services/electrical', '/services/hvac',
  '/services/pool', '/services/gardening'
]);

const secondaryKeywords = (topic.secondary_keywords || '').split(/;\s*/).filter(Boolean).join('; ');

let rendered = String(systemPromptTemplate);
const replace = (k, v) => { rendered = rendered.split('{{' + k + '}}').join(v ?? ''); };

replace('TITLE', topic.title);
replace('SLUG', topic.slug);
replace('PRIMARY_KEYWORD', topic.primary_keyword);
replace('SECONDARY_KEYWORDS', secondaryKeywords);
replace('BUCKET', topic.bucket);
replace('TARGET_WORD_COUNT', String(topic.target_word_count || 1500));
replace('SEARCH_INTENT', topic.search_intent || 'informational');
replace('BRIEF', topic.brief || '');
replace('TODAY_DATE', today);
replace('AVAILABLE_INTERNAL_LINKS', availableInternalLinks);
replace('COVER_IMAGE_URL', coverUrl);
replace('COVER_IMAGE_ALT', coverAlt);

return {
  json: {
    topic_id: topic.topic_id,
    title: topic.title,
    slug: topic.slug,
    bucket: topic.bucket,
    record_id: $('Airtable: Get next topic').item.json.id,
    cover_url: coverUrl,
    cover_alt: coverAlt,
    today,
    system_prompt: rendered
  }
};

// Extract Claude's response. The article should be a complete markdown
// document (frontmatter + body). Strip markdown code fences if present.
const response = $input.item.json;
let content = '';

if (response.content && Array.isArray(response.content)) {
  content = response.content.map(c => c.text || '').join('\n');
} else if (typeof response === 'string') {
  content = response;
}

content = content.trim();
// Strip ```markdown ... ``` fences
if (content.startsWith('```')) {
  content = content.replace(/^```[a-z]*\n/, '').replace(/```\s*$/, '').trim();
}

const ctx = $('Build context').item.json;

// Base64 encode for GitHub API.
const contentBase64 = Buffer.from(content, 'utf8').toString('base64');

return {
  json: {
    slug: ctx.slug,
    title: ctx.title,
    bucket: ctx.bucket,
    record_id: ctx.record_id,
    today: ctx.today,
    markdown: content,
    markdown_base64: contentBase64,
    branch_name: 'drafts/' + ctx.slug,
    file_path: 'content/blog/' + ctx.slug + '.md'
  }
};

